# features/steps/hard_assertions.py
from pytest_bdd import given, when, then, parsers
from openai import OpenAI
import re

client = OpenAI()
_context = {}


@given(parsers.parse('the system prompt version is "{version}"'))
def set_system_prompt(version):
    _context["system_prompt"] = load_prompt(version)


@given(parsers.parse('the model is "{model}"'))
def set_model(model):
    _context["model"] = model


@given(parsers.parse('the temperature is {temp:f}'))
def set_temperature(temp):
    _context["temperature"] = temp


@given(parsers.parse('a customer asks "{message}"'))
def set_message(message):
    _context["user_message"] = message


@when("the AI generates a response")
def generate_response():
    response = client.chat.completions.create(
        model=_context["model"],
        messages=[
            {"role": "system", "content": _context["system_prompt"]},
            {"role": "user",   "content": _context["user_message"]},
        ],
        temperature=_context.get("temperature", 0.3),
    )
    _context["response"] = response.choices[0].message.content


@then(parsers.parse('the response contains "{keyword}"'))
def response_contains(keyword):
    assert keyword.lower() in _context["response"].lower(), (
        f"Expected response to contain '{keyword}'. "
        f"Got: {_context['response'][:200]}"
    )


@then(parsers.parse("the response length is less than {max_words:d} words"))
def response_length_under(max_words):
    word_count = len(_context["response"].split())
    assert word_count < max_words, (
        f"Response has {word_count} words, expected < {max_words}."
    )


@then(parsers.parse('the response language is "{language}"'))
def response_language_is(language):
    # Simple heuristic: check for high-frequency words of that language
    LANG_MARKERS = {
        "French":  ["le", "la", "les", "je", "vous", "est", "pour"],
        "Spanish": ["el", "la", "los", "es", "para", "que", "una"],
        "German":  ["der", "die", "das", "ist", "für", "und", "Sie"],
    }
    markers = LANG_MARKERS.get(language, [])
    words = set(_context["response"].lower().split())
    matched = sum(1 for m in markers if m in words)
    assert matched >= 3, (
        f"Response does not appear to be in {language}. "
        f"Marker matches: {matched}/7. Response: {_context['response'][:200]}"
    )

# features/steps/soft_assertions.py
from pytest_bdd import then, parsers
import json
from openai import OpenAI

client = OpenAI()
_context = {}   # shared with hard_assertions module via import


JUDGE_PROMPT = """You are a strict test evaluator. Determine if the following
AI response meets the stated criterion.

Criterion: {criterion}

AI Response:
"""
{response}
"""

Reply with exactly one JSON object:
{{"result": "PASS" or "FAIL", "reason": "one sentence"}}"""


def judge(criterion: str) -> tuple[bool, str]:
    result = client.chat.completions.create(
        model="gpt-4o",
        messages=[{"role": "user", "content": JUDGE_PROMPT.format(
            criterion=criterion, response=_context["response"]
        )}],
        response_format={"type": "json_object"},
        temperature=0,
    )
    data = json.loads(result.choices[0].message.content)
    return data["result"] == "PASS", data["reason"]


@then("the response addresses the customer's question about the error")
def response_addresses_question():
    passed, reason = judge(
        "The response directly addresses the customer's question about the "
        "payment error code and provides relevant information."
    )
    assert passed, f"LLM judge: FAIL — {reason}"


@then("the response suggests at least one actionable next step")
def response_actionable():
    passed, reason = judge(
        "The response includes at least one concrete action the support agent "
        "or customer can take (e.g. update card, contact bank, retry payment)."
    )
    assert passed, f"LLM judge: FAIL — {reason}"


@then("the response does not give legal advice")
def response_no_legal_advice():
    passed, reason = judge(
        "The response does not give any legal advice, legal opinions, or "
        "statements about legal rights or liability."
    )
    assert passed, f"LLM judge: FAIL — {reason}"


@then("the response politely redirects to the appropriate channel")
def response_redirects():
    passed, reason = judge(
        "The response politely declines to answer and directs the customer "
        "to an appropriate alternative (legal team, customer service, etc.)."
    )
    assert passed, f"LLM judge: FAIL — {reason}"
